  ) AS rq(id, symbol, source_symbol, source_exchange, source_url, source_date_range, difficulty, base_date, chart_data, actual_next_candles, correct_answer, ai_explanation, rule_score, pattern_evidence, pattern_score_breakdown)
)
INSERT INTO questions (
  id,
  pattern_id,
  symbol,
  market,
  timeframe,
  difficulty,
  market_regime,
  base_date,
  chart_data,
  actual_next_candles,
  correct_answer,
  ai_explanation,
  rule_score,
  public_accuracy,
  pattern_evidence,
  pattern_score_breakdown,
  is_synthetic,
  source_name,
  source_url,
  source_symbol,
  source_exchange,
  source_date_range
)
SELECT
  rq.id,
  p.id,
  rq.symbol,
  'KRX',
  '1w',
  rq.difficulty,
  'bull'::market_regime,
  rq.base_date,
  rq.chart_data,
  rq.actual_next_candles,
  rq.correct_answer,
  rq.ai_explanation,
  rq.rule_score,
  0.7000,
  rq.pattern_evidence,
  rq.pattern_score_breakdown,
  false,
  'Yahoo Finance chart API',
  rq.source_url,
  rq.source_symbol,
  rq.source_exchange,
  rq.source_date_range
FROM real_questions rq
CROSS JOIN pattern_row p
ON CONFLICT (id) DO UPDATE SET
  pattern_id = EXCLUDED.pattern_id,
  symbol = EXCLUDED.symbol,
  market = EXCLUDED.market,
  timeframe = EXCLUDED.timeframe,
  difficulty = EXCLUDED.difficulty,
  market_regime = EXCLUDED.market_regime,
  base_date = EXCLUDED.base_date,
  chart_data = EXCLUDED.chart_data,
  actual_next_candles = EXCLUDED.actual_next_candles,
  correct_answer = EXCLUDED.correct_answer,
  ai_explanation = EXCLUDED.ai_explanation,
  rule_score = EXCLUDED.rule_score,
  public_accuracy = EXCLUDED.public_accuracy,
  pattern_evidence = EXCLUDED.pattern_evidence,
  pattern_score_breakdown = EXCLUDED.pattern_score_breakdown,
  is_synthetic = EXCLUDED.is_synthetic,
  source_name = EXCLUDED.source_name,
  source_url = EXCLUDED.source_url,
  source_symbol = EXCLUDED.source_symbol,
  source_exchange = EXCLUDED.source_exchange,
  source_date_range = EXCLUDED.source_date_range,
  is_active = true,
  updated_at = now();


UPDATE questions
SET is_active = false,
    updated_at = now()
WHERE pattern_id = (SELECT id FROM patterns WHERE slug = 'early-stage2' LIMIT 1)
  AND source_name = 'Yahoo Finance chart API'
  AND is_synthetic = false
  AND id NOT IN ('33000000-0000-0000-0000-000000000001'::uuid, '33000000-0000-0000-0000-000000000002'::uuid, '33000000-0000-0000-0000-000000000003'::uuid, '33000000-0000-0000-0000-000000000004'::uuid, '33000000-0000-0000-0000-000000000005'::uuid, '33000000-0000-0000-0000-000000000006'::uuid, '33000000-0000-0000-0000-000000000007'::uuid, '33000000-0000-0000-0000-000000000008'::uuid, '33000000-0000-0000-0000-000000000009'::uuid, '33000000-0000-0000-0000-000000000010'::uuid);
